const body = $input.item.json.body ?? $input.item.json;

const event = body.event;
const instance = body.instance;
const data = body.data;

// Только messages.upsert
if (event !== 'messages.upsert') return [];

const key = data?.key ?? {};
const message = data?.message ?? {};

// Игнорировать свои и групповые
if (key.fromMe === true) return [];
if (!key.remoteJid || key.remoteJid.endsWith('@g.us')) return [];

// Номер без суффикса
const phone = key.remoteJid.replace(/@s\.whatsapp\.net$/, '').replace(/@c\.us$/, '');

// Тип и контент
const msgType = data.messageType ?? 'conversation';
let messageType = 'text';
let content = '';
let mediaUrl = null;

if (msgType === 'conversation' || msgType === 'extendedTextMessage') {
  messageType = 'text';
  content = message.conversation ?? message.extendedTextMessage?.text ?? '';
} else if (msgType === 'imageMessage') {
  messageType = 'image';
  content = message.imageMessage?.caption ?? '[Фото]';
  mediaUrl = message.imageMessage?.url ?? null;
} else if (msgType === 'audioMessage') {
  messageType = 'audio';
  content = '[Голосовое сообщение]';
  mediaUrl = message.audioMessage?.url ?? null;
} else if (msgType === 'documentMessage') {
  messageType = 'file';
  content = message.documentMessage?.fileName ?? '[Файл]';
  mediaUrl = message.documentMessage?.url ?? null;
} else if (msgType === 'videoMessage') {
  messageType = 'video';
  content = message.videoMessage?.caption ?? '[Видео]';
  mediaUrl = message.videoMessage?.url ?? null;
} else if (msgType === 'locationMessage') {
  messageType = 'location';
  const loc = message.locationMessage;
  content = `[Геолокация: ${loc?.degreesLatitude},${loc?.degreesLongitude}]`;
} else if (msgType === 'contactMessage') {
  messageType = 'contact';
  content = message.contactMessage?.displayName ?? '[Контакт]';
} else {
  content = `[${msgType}]`;
}

return [{
  json: {
    instance,
    from_phone: phone,
    push_name: data.pushName ?? null,
    message_id: key.id,
    message_type: messageType,
    content,
    media_url: mediaUrl,
    timestamp: data.messageTimestamp ?? Math.floor(Date.now() / 1000)
  }
}];
